// ============================================================
// MAIN SEED FUNCTION
// ============================================================
async function seedJambSubjects() {
  try {
    await mongoose.connect(MONGO_URI);
    console.log('Connected to MongoDB');

    // Find teacher or admin
    let teacher = await User.findOne({ role: 'teacher' });
    if (!teacher) teacher = await User.findOne({ role: 'admin' });
    if (!teacher) {
      console.error('No teacher or admin found. Run seed.js first.');
      process.exit(1);
    }
    console.log(`Using "${teacher.username}" as question owner`);

    let totalAdded   = 0;
    let totalSkipped = 0;

    for (const subjectName of Object.keys(allQuestions)) {
      console.log(`\nProcessing: ${subjectName}`);

      // Create subject if it doesn't exist
      let subject = await Subject.findOne({ name: subjectName });
      if (!subject) {
        subject = await Subject.create({
          name:        subjectName,
          description: `${subjectName} — JAMB standard syllabus`
        });
        console.log(`  Created subject: ${subjectName}`);
      } else {
        console.log(`  Subject already exists: ${subjectName}`);
      }

      // Create syllabus topics
      const syllabusMap = {};
      const topics      = subjectTopics[subjectName] || [];

      for (const t of topics) {
        let existing = await Syllabus.findOne({ subjectId: subject._id, topic: t.topic });
        if (!existing) {
          existing = await Syllabus.create({
            subjectId:   subject._id,
            topic:       t.topic,
            description: t.description
          });
          console.log(`  Created topic: ${t.topic}`);
        }
        syllabusMap[t.topic] = existing._id;
      }

      // Seed questions
      let added   = 0;
      let skipped = 0;

      for (const q of allQuestions[subjectName]) {
        const exists = await Question.findOne({
          subjectId:    subject._id,
          questionText: q.questionText
        });
        if (!exists) {
          await Question.create({
            teacherId:    teacher._id,
            subjectId:    subject._id,
            syllabusId:   syllabusMap[q.topic] || null,
            questionText: q.questionText,
            options:      q.options,
            answer:       q.answer,
            explanation:  q.explanation
          });
          added++;
        } else {
          skipped++;
        }
      }

      console.log(`  Added: ${added} | Skipped: ${skipped}`);
      totalAdded   += added;
      totalSkipped += skipped;
    }

    console.log('\n================================================');
    console.log('seedJambSubjects.js — Completed!');
    console.log(`Total added  : ${totalAdded}`);
    console.log(`Total skipped: ${totalSkipped}`);
    console.log('');
    console.log('Breakdown:');
    console.log('  Government : 150 questions');
    console.log('  Physics    : 150 questions');
    console.log('  CRS        : 150 questions');
    console.log('  TOTAL      : 450 questions');
    console.log('================================================');

    await mongoose.disconnect();
    process.exit(0);
  } catch (error) {
    console.error('Seed error:', error.message);
    await mongoose.disconnect();
    process.exit(1);
  }
}

seedJambSubjects();
